def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, bin_capacity in enumerate(bins):
        if bin_capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / bin_capacity
        if ratio > 1:
            priorities[i] = np.abs(ratio) * 10
        elif ratio == 1:
            priorities[i] = 0
        else:
            acc = 0
            temp = ratio
            for _ in range(5):
                if temp <= 0:
                    acc += 10
                else:
                    acc += np.log(temp + 1)
                temp *= 2
            priorities[i] = acc
        if bin_capacity % 2 == 0:
            priorities[i] *= 0.9
        else:
            priorities[i] *= 1.1
    min_priority = np.min(priorities[priorities != float('inf')]) if np.any(priorities != float('inf')) else 0
    for i in range(len(priorities)):
        if priorities[i] == float('inf'):
            priorities[i] = min_priority * 1.5
    return priorities
